function [ucost, ttake] = takeoff(ptake, ftake, materials)
    % calculate unit cost
    ucost = sum(ptake(:,1:end-1)) ./ sum(ptake(:,1:end-1) .* [1;1;1]);

    % check if there is enough information to calculate future cost
    if size(ptake,1) < size(ftake,1)
        ttake = "Info is not enough";
        return;
    end

    % calculate future costs
    fc = ftake .* ucost';
    fc_tot = sum(fc, 2);

    % combine future and past data into ttake
    ttake = [materials' num2cell([ptake(:,1:end-1) fc fc_tot]) "cost"];
end
